+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum DenseFactorCacheResult {
+    Hit,
+    MissInserted,
+    MissEvicted,
+}
+
+#[derive(Debug, Clone, PartialEq, Eq)]
+enum DenseFactorCacheLookup {
+    Hit(DenseFactorArtifact),
+    MissNoEntry,
+    MissFingerprintCollision,
+}
